// =============================================================================
// PA-Pipeline-Setup.cs
// Self-contained WinForms installer for PA Pipeline.
// PS2EXE is bundled directly - no internet connection required.
// Compiled by Build-Setup.bat using csc.exe (built into Windows).
//
// Installs to Program Files, so this installer self-elevates via UAC.
//
// !! ICON REMINDER !!
// When you have a .ico file, update Build-Setup.bat to pass:
//   /win32icon:"C:\path\to\your.ico"
// to the csc.exe command, then rebuild.
// =============================================================================

using System;
using System.ComponentModel;
using System.Diagnostics;
using System.Drawing;
using System.IO;
using System.IO.Compression;
using System.Reflection;
using System.Security.Principal;
using System.Text;
using System.Threading;
using System.Windows.Forms;
using Microsoft.Win32;

[assembly: AssemblyTitle("PA Pipeline Setup")]
[assembly: AssemblyDescription("Installer for PA Pipeline")]
[assembly: AssemblyCompany("SCI")]
[assembly: AssemblyProduct("PA Pipeline")]
[assembly: AssemblyVersion("1.0.0.0")]

namespace PASetup
{
    static class Program
    {
        // ── Default pip packages (also written into the project_config.json template) ──
        public static readonly string[] PipPackages = new string[] {
            "mpxj", "jpype1", "pandas", "pyarrow", "openpyxl",
            "matplotlib", "reportlab", "pypdf", "pikepdf", "pdfplumber"
        };

        // ── Embedded PA-Pipeline.ps1 ─────────────────────────────────────────
        public const string APP_SOURCE_B64 = "";

        // ── Embedded PS2EXE module files ─────────────────────────────────────
        public const string PS2EXE_PS1_B64    = "";
        public const string PS2EXE_PSD1_B64   = "";
        public const string PS2EXE_PSM1_B64   = "";
        public const string PS2EXE_WINEXE_B64 = "";

        // ── Embedded Python pipeline stage scripts (Stage : filename : base64) ──
        public const string SCRIPT_C_B64 = "";
        public const string SCRIPT_D_B64 = "";
        public const string SCRIPT_E_B64 = "";
        public const string SCRIPT_F_B64 = "";
        public const string SCRIPT_G_B64 = "";
        public const string SCRIPT_H_B64 = "";
        public const string SCRIPT_K_B64 = "";
        public const string SCRIPT_L_B64 = "";
        public const string SCRIPT_M_B64 = "";

        public static string[][] GetStageScripts()
        {
            return new string[][] {
                new string[] { "extract_snapshots.py",    SCRIPT_C_B64 },
                new string[] { "resolve_wbs.py",           SCRIPT_D_B64 },
                new string[] { "construction_variance.py", SCRIPT_E_B64 },
                new string[] { "critical_path.py",         SCRIPT_F_B64 },
                new string[] { "forward_look.py",          SCRIPT_G_B64 },
                new string[] { "buyout_analysis.py",       SCRIPT_H_B64 },
                new string[] { "generate_charts.py",       SCRIPT_K_B64 },
                new string[] { "assemble_pdf.py",          SCRIPT_L_B64 },
                new string[] { "run_qc.py",                SCRIPT_M_B64 }
            };
        }

        // The bundled CPython installer (~26MB) is embedded as a .NET PE
        // resource via csc.exe's /resource: flag (wired up in Build-Setup.bat
        // and Embed-Sources.ps1), NOT as a base64 string constant like the
        // smaller files above. A real test compile showed why: csc.exe
        // (v4.0.30319) hard-fails on ~36M characters of string-literal data
        // with "No logical space left to create more user strings" - that's
        // the .NET #US metadata heap, and splitting into smaller literals
        // doesn't help since they all still share that one heap. A PE
        // resource isn't subject to that limit at all - confirmed with an
        // isolated compile-and-read-back test against the real 26MB file
        // (byte-for-byte SHA256 match) before wiring this in for real.
        public const string PYTHON_INSTALLER_RESOURCE_NAME = "PASetup.PythonInstaller.exe";

        public static byte[] GetPythonInstallerBytes()
        {
            using (Stream s = Assembly.GetExecutingAssembly().GetManifestResourceStream(PYTHON_INSTALLER_RESOURCE_NAME))
            {
                if (s == null)
                    throw new Exception("Embedded Python installer resource not found (" + PYTHON_INSTALLER_RESOURCE_NAME + "). Was this exe compiled with the /resource: flag?");
                using (MemoryStream ms = new MemoryStream())
                {
                    s.CopyTo(ms);
                    return ms.ToArray();
                }
            }
        }

        // Eclipse Temurin JRE (OpenJDK build, redistribution-friendly license -
        // unlike Oracle's JRE) for the bundled JVM Stage C needs via MPXJ/JPype.
        // Embedded the same way as the Python installer and for the same reason:
        // a ~47MB zip is also far too large for the base64-string-constant
        // pattern. Read directly into a FileStream in RunInstall() rather than
        // buffered through a byte[] first - no GetJavaRuntimeBytes() helper
        // needed since there's only the one call site.
        public const string JAVA_RUNTIME_RESOURCE_NAME = "PASetup.JavaRuntime.zip";

        [STAThread]
        static void Main()
        {
            if (!IsAdministrator())
            {
                try
                {
                    ProcessStartInfo psi = new ProcessStartInfo();
                    psi.FileName = Application.ExecutablePath;
                    psi.UseShellExecute = true;
                    psi.Verb = "runas";
                    Process.Start(psi);
                }
                catch (Win32Exception)
                {
                    MessageBox.Show(
                        "PA Pipeline Setup needs to install to Program Files, which requires administrator rights.\n\nPlease accept the elevation prompt to continue.",
                        "Administrator Rights Required", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                }
                return;
            }

            Application.EnableVisualStyles();
            Application.SetCompatibleTextRenderingDefault(false);
            Application.Run(new SetupForm());
        }

        static bool IsAdministrator()
        {
            WindowsIdentity identity = WindowsIdentity.GetCurrent();
            WindowsPrincipal principal = new WindowsPrincipal(identity);
            return principal.IsInRole(WindowsBuiltInRole.Administrator);
        }
    }

