        void BtnBrowse_Click(object sender, EventArgs e)
        {
            FolderBrowserDialog dlg = new FolderBrowserDialog();
            dlg.Description = "Choose install location for PA Pipeline";
            dlg.SelectedPath = installDir;
            dlg.ShowNewFolderButton = true;
            if (dlg.ShowDialog() == DialogResult.OK) {
                installDir = dlg.SelectedPath;
                tbInstallDir.Text = installDir;
            }
        }

        void BtnInstall_Click(object sender, EventArgs e)
        {
            if (installing) return;
            if (string.IsNullOrEmpty(installDir)) {
                MessageBox.Show("Please choose an install location.", "Setup",
                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            installing = true;
            btnInstall.Enabled   = false;
            btnBrowse.Enabled    = false;
            tbInstallDir.Enabled = false;
            pgBar.Visible        = true;
            lblStatus.Visible    = true;
            lblDetail.Visible    = true;
            btnInstall.Text      = "Installing...";
            Thread t = new Thread(RunInstall);
            t.IsBackground = true;
            t.Start();
        }

        void SetStatus(string status, string detail, int progress)
        {
            if (InvokeRequired) {
                Invoke(new Action<string, string, int>(SetStatus), status, detail, progress);
                return;
            }
            lblStatus.Text = status;
            lblDetail.Text = detail;
            if (progress >= 0) pgBar.Value = Math.Min(100, progress);
            Application.DoEvents();
        }

        void RunInstall()
        {
            string exePath    = Path.Combine(installDir, "PA-Pipeline.exe");
            string uninstPath = Path.Combine(installDir, "Uninstall.exe");
            string tempPs1    = Path.Combine(Path.GetTempPath(),
                "PA-" + Guid.NewGuid().ToString("N").Substring(0, 8) + ".ps1");
            string ps2exeDir  = Path.Combine(Path.GetTempPath(),
                "ps2exe-" + Guid.NewGuid().ToString("N").Substring(0, 8));
            // venv + project_config.json live OUTSIDE installDir, in the per-user
            // LocalAppData profile - installDir (Program Files) is only writable by
            // this elevated installer, never by the app itself at normal runtime.
            string dataRoot   = Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "PA-Pipeline");
            string venvDir    = Path.Combine(dataRoot, "venv");
            string venvPython = Path.Combine(venvDir, "Scripts\\python.exe");
            bool venvOk     = false;
            bool packagesOk = false;

            try {
                // Step 1 - create install dir + the per-user writable data dir
                SetStatus("Step 1 of 11 - Preparing install folder...", installDir, 3);
                Directory.CreateDirectory(installDir);
                Directory.CreateDirectory(dataRoot);

                // Step 2 - extract app ps1 + ps2exe module to temp; stage scripts to install dir
                SetStatus("Step 2 of 11 - Extracting files...", "", 10);

                byte[] appBytes = Convert.FromBase64String(Program.APP_SOURCE_B64);
                File.WriteAllBytes(tempPs1, appBytes);

                Directory.CreateDirectory(ps2exeDir);
                File.WriteAllBytes(Path.Combine(ps2exeDir, "ps2exe.ps1"),
                    Convert.FromBase64String(Program.PS2EXE_PS1_B64));
                File.WriteAllBytes(Path.Combine(ps2exeDir, "ps2exe.psd1"),
                    Convert.FromBase64String(Program.PS2EXE_PSD1_B64));
                File.WriteAllBytes(Path.Combine(ps2exeDir, "ps2exe.psm1"),
                    Convert.FromBase64String(Program.PS2EXE_PSM1_B64));
                File.WriteAllBytes(Path.Combine(ps2exeDir, "Win-PS2EXE.exe"),
                    Convert.FromBase64String(Program.PS2EXE_WINEXE_B64));

                string[][] stageScripts = Program.GetStageScripts();
                foreach (string[] entry in stageScripts) {
                    File.WriteAllBytes(Path.Combine(installDir, entry[0]), Convert.FromBase64String(entry[1]));
                }

                SetStatus("Step 2 of 11 - Files extracted.", "", 18);

                // Step 3 - compile using the local PS2EXE copy
                SetStatus("Step 3 of 11 - Compiling PA-Pipeline.exe...",
                          "This takes about 20-30 seconds...", 25);

                StringBuilder compScript = new StringBuilder();
                compScript.AppendLine("Import-Module '" + ps2exeDir + "\\ps2exe.psd1' -Force");
                compScript.AppendLine("$params = @{");
                compScript.AppendLine("  InputFile   = '" + tempPs1  + "'");
                compScript.AppendLine("  OutputFile  = '" + exePath  + "'");
                compScript.AppendLine("  NoConsole   = $true");
                compScript.AppendLine("  Title       = 'PA Pipeline'");
                compScript.AppendLine("  Product     = 'PA Pipeline'");
                compScript.AppendLine("  Description = 'Configure, run and review the PA construction schedule analytics pipeline'");
                compScript.AppendLine("  Company     = 'SCI'");
                compScript.AppendLine("  Version     = '1.0.0.0'");
                compScript.AppendLine("}");
                compScript.AppendLine("Invoke-ps2exe @params");

                string err2;
                string r2 = RunPS(compScript.ToString(), out err2);
                if (r2 == null || !File.Exists(exePath))
                    throw new Exception("Compilation failed:\n" + err2);

                try { File.Delete(tempPs1); } catch {}
                try { Directory.Delete(ps2exeDir, true); } catch {}

                // Step 4 - install the bundled CPython runtime to an app-owned path.
                // Deliberately does NOT touch PATH or rely on a "py"/"python" lookup -
                // that lookup is exactly what resolves to the Microsoft Store alias
                // stub on a clean Windows box (exit code 9009, no real interpreter),
                // which used to make venv creation fail silently. PrependPath=0 keeps
                // this runtime invisible to every other app on the machine.
                string pythonRuntimeDir = Path.Combine(installDir, "python-runtime");
                string bundledPython    = Path.Combine(pythonRuntimeDir, "python.exe");
                SetStatus("Step 4 of 11 - Installing bundled Python runtime...", pythonRuntimeDir, 35);
                string pyInstallerTemp = Path.Combine(Path.GetTempPath(),
                    "PA-py-" + Guid.NewGuid().ToString("N").Substring(0, 8) + ".exe");
                bool pythonRuntimeOk = false;
                try {
                    File.WriteAllBytes(pyInstallerTemp, Program.GetPythonInstallerBytes());
                    string pyInstallArgs =
                        "/quiet InstallAllUsers=0 TargetDir=\"" + pythonRuntimeDir + "\" " +
                        "PrependPath=0 Include_pip=1 Include_venv=1";
                    string pyInstallOut;
                    int pyInstallCode = RunNative(pyInstallerTemp, pyInstallArgs, out pyInstallOut);
                    pythonRuntimeOk = (pyInstallCode == 0 && File.Exists(bundledPython));
                    if (!pythonRuntimeOk)
                        SetStatus("Step 4 of 11 - Bundled Python install failed (continuing).", pyInstallOut, 45);
                } finally {
                    try { File.Delete(pyInstallerTemp); } catch {}
                }

                // Step 5 - install the bundled Java runtime (JRE) to an app-owned path.
                // Stage C needs a JVM (via MPXJ/JPype) to read .mpp/.xml snapshots.
                // Left to its own auto-detection, JPype can pick an incompatible JVM
                // (e.g. a 32-bit one) when multiple Javas are on the machine, even
                // with a working 64-bit JVM also present - bundling one removes that
                // ambiguity the same way the bundled Python runtime does.
                string javaRuntimeDir = Path.Combine(installDir, "java-runtime");
                bool javaRuntimeOk = false;
                SetStatus("Step 5 of 11 - Installing bundled Java runtime...", javaRuntimeDir, 38);
                string javaZipTemp = Path.Combine(Path.GetTempPath(),
                    "PA-jre-" + Guid.NewGuid().ToString("N").Substring(0, 8) + ".zip");
                string javaExtractTemp = Path.Combine(Path.GetTempPath(),
                    "PA-jre-extract-" + Guid.NewGuid().ToString("N").Substring(0, 8));
                try {
                    using (Stream rs = Assembly.GetExecutingAssembly().GetManifestResourceStream(Program.JAVA_RUNTIME_RESOURCE_NAME)) {
                        if (rs == null)
                            throw new Exception("Embedded Java runtime resource not found (" + Program.JAVA_RUNTIME_RESOURCE_NAME + ").");
                        using (FileStream fs = new FileStream(javaZipTemp, FileMode.Create))
                            rs.CopyTo(fs);
                    }
                    ZipFile.ExtractToDirectory(javaZipTemp, javaExtractTemp);
                    // The Temurin zip wraps everything in one version-named top-level
                    // folder (e.g. jdk-21.0.11+10-jre) - move its contents up rather
                    // than hardcode a version string that will go stale on the next
                    // JRE update.
                    string[] topDirs = Directory.GetDirectories(javaExtractTemp);
                    if (topDirs.Length != 1)
                        throw new Exception("Expected exactly one top-level folder in the Java runtime zip, found " + topDirs.Length + ".");
                    if (Directory.Exists(javaRuntimeDir)) Directory.Delete(javaRuntimeDir, true);
                    Directory.Move(topDirs[0], javaRuntimeDir);
                    javaRuntimeOk = File.Exists(Path.Combine(javaRuntimeDir, "bin", "java.exe"));
                    if (!javaRuntimeOk)
                        SetStatus("Step 5 of 11 - Bundled Java runtime install failed (continuing).", "java.exe not found after extraction", 42);
                } catch (Exception jex) {
                    SetStatus("Step 5 of 11 - Bundled Java runtime install failed (continuing).", jex.Message, 42);
                } finally {
                    try { File.Delete(javaZipTemp); } catch {}
                    try { if (Directory.Exists(javaExtractTemp)) Directory.Delete(javaExtractTemp, true); } catch {}
                }

                // Step 6 - create the venv using the bundled runtime (non-fatal if it
                // fails - the app's own Settings tab can create it later, with an
                // advanced override path if the bundled runtime is unusable)
                if (pythonRuntimeOk) {
                    SetStatus("Step 6 of 11 - Creating virtual environment...", venvDir, 50);
                    string venvArgs = "-m venv \"" + venvDir + "\"";
                    string nOut;
                    int code = RunNative(bundledPython, venvArgs, out nOut);
                    venvOk = (code == 0 && File.Exists(venvPython));
                    if (!venvOk) SetStatus("Step 6 of 11 - Venv creation failed (continuing).", nOut, 55);
                } else {
                    SetStatus("Step 6 of 11 - Skipped (no bundled Python runtime).",
                              "You can create the venv later from the app's Settings tab.", 55);
                }

                // Step 7 - install packages into the venv (also non-fatal)
                if (venvOk) {
                    SetStatus("Step 7 of 11 - Installing Python packages...",
                              "This can take a few minutes...", 60);
                    string pkgArgs = "-m pip install " + string.Join(" ", Program.PipPackages);
                    string pOut;
                    int pcode = RunNative(venvPython, pkgArgs, out pOut);
                    packagesOk = (pcode == 0);
                    if (!packagesOk) SetStatus("Step 7 of 11 - Package install failed (continuing).", pOut, 80);
                } else {
                    SetStatus("Step 7 of 11 - Skipped (no venv).", "", 80);
                }

                // Step 8 - write project_config.json template (only if one doesn't already
                // exist - re-running the installer must never clobber a configured project)
                string configPath = Path.Combine(dataRoot, "project_config.json");
                if (!File.Exists(configPath)) {
                    SetStatus("Step 8 of 11 - Writing project_config.json...", "", 85);
                    string venvVersion = "";
                    if (venvOk) {
                        string vOut;
                        int vcode = RunNative(venvPython, "--version", out vOut);
                        if (vcode == 0) venvVersion = vOut.Trim();
                    }
                    string configJson = BuildConfigJson(venvDir, venvPython, venvOk, packagesOk, venvVersion,
                                                         pythonRuntimeOk ? bundledPython : "",
                                                         javaRuntimeOk ? javaRuntimeDir : "");
                    File.WriteAllText(configPath, configJson, new UTF8Encoding(false));
                } else {
                    SetStatus("Step 8 of 11 - project_config.json already exists, leaving it untouched.", configPath, 85);
                }

                SetStatus("Step 9 of 11 - Creating shortcuts...", "", 90);

                // Desktop shortcut
                string desk = Environment.GetFolderPath(Environment.SpecialFolder.DesktopDirectory);
                CreateShortcut(Path.Combine(desk, "PA Pipeline.lnk"), exePath,
                               "PA Pipeline - Configure, run and review the schedule analytics pipeline");

                // Start Menu
                string smDir = Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.Programs),
                    "PA Pipeline");
                Directory.CreateDirectory(smDir);
                CreateShortcut(Path.Combine(smDir, "PA Pipeline.lnk"), exePath,
                               "PA Pipeline - Configure, run and review the schedule analytics pipeline");
                CreateShortcut(Path.Combine(smDir, "Uninstall PA Pipeline.lnk"),
                               uninstPath, "Uninstall PA Pipeline");

                // Write uninstaller
                SetStatus("Step 10 of 11 - Writing uninstaller...", "", 94);
                WriteUninstaller(uninstPath, installDir, dataRoot);

                // Registry
                SetStatus("Step 11 of 11 - Registering with Windows...", "", 97);
                WriteRegistry(installDir, exePath, uninstPath);

                SetStatus("", "", 100);
                Invoke(new Action<string>(ShowFinished), exePath);
            }
            catch (Exception ex) {
                try { File.Delete(tempPs1); } catch {}
                try { Directory.Delete(ps2exeDir, true); } catch {}
                Invoke(new Action<string>(ShowError), ex.Message);
            }
        }

        void ShowFinished(string exePath)
        {
            MessageBox.Show(
                "PA Pipeline installed successfully!\n\nYou can launch it from the Desktop shortcut, the Start Menu, or:\n" + exePath,
                "Installation Complete", MessageBoxButtons.OK, MessageBoxIcon.Information);
            Close();
        }

        void ShowError(string message)
        {
            MessageBox.Show("Installation failed:\n\n" + message, "Setup Error",
                MessageBoxButtons.OK, MessageBoxIcon.Error);
            installing           = false;
            btnInstall.Enabled   = true;
            btnBrowse.Enabled    = true;
            tbInstallDir.Enabled = true;
            btnInstall.Text      = "  Install Now  >";
        }

        string RunPS(string script, out string stderr)
        {
            string tmpScript = Path.Combine(Path.GetTempPath(),
                "pasetup-" + Guid.NewGuid().ToString("N").Substring(0, 8) + ".ps1");
            try {
                File.WriteAllText(tmpScript, script, Encoding.UTF8);
                ProcessStartInfo psi = new ProcessStartInfo();
                psi.FileName               = "powershell.exe";
                psi.Arguments              = "-NonInteractive -NoProfile -ExecutionPolicy Bypass -File \"" + tmpScript + "\"";
                psi.UseShellExecute        = false;
                psi.RedirectStandardOutput = true;
                psi.RedirectStandardError  = true;
                psi.CreateNoWindow         = true;
                Process p = Process.Start(psi);
                string stdout = p.StandardOutput.ReadToEnd();
                stderr        = p.StandardError.ReadToEnd();
                p.WaitForExit();
                try { File.Delete(tmpScript); } catch {}
                return p.ExitCode == 0 ? stdout : null;
            }
            catch (Exception ex) {
                try { File.Delete(tmpScript); } catch {}
                stderr = ex.Message;
                return null;
            }
        }

        int RunNative(string fileName, string arguments, out string output)
        {
            try {
                ProcessStartInfo psi = new ProcessStartInfo();
                psi.FileName               = fileName;
                psi.Arguments              = arguments;
                psi.UseShellExecute        = false;
                psi.RedirectStandardOutput = true;
                psi.RedirectStandardError  = true;
                psi.CreateNoWindow         = true;
                Process p = Process.Start(psi);
                string stdout = p.StandardOutput.ReadToEnd();
                string stderr = p.StandardError.ReadToEnd();
                p.WaitForExit();
                output = stdout + stderr;
                return p.ExitCode;
            }
            catch (Exception ex) {
                output = ex.Message;
                return -1;
            }
        }

        void CreateShortcut(string lnkPath, string targetPath, string description)
        {
            string cmd =
                "$s=(New-Object -COM WScript.Shell).CreateShortcut('" + lnkPath.Replace("'","''") + "');" +
                "$s.TargetPath='" + targetPath.Replace("'","''") + "';" +
                "$s.Description='" + description.Replace("'","''") + "';" +
                "$s.Save()";
            string err;
            RunPS(cmd, out err);
        }

        void WriteRegistry(string dir, string exePath, string uninstPath)
        {
            try {
                RegistryKey key = Registry.CurrentUser.CreateSubKey(
                    "Software\\Microsoft\\Windows\\CurrentVersion\\Uninstall\\PAPipeline");
                if (key != null) {
                    key.SetValue("DisplayName", "PA Pipeline");
                    key.SetValue("DisplayVersion", "1.0.0");
                    key.SetValue("Publisher", "SCI");
                    key.SetValue("InstallLocation", dir);
                    key.SetValue("UninstallString", uninstPath);
                    key.SetValue("NoModify", 1, RegistryValueKind.DWord);
                    key.SetValue("NoRepair", 1, RegistryValueKind.DWord);
                    key.Close();
                }
            } catch {}
        }

        void WriteUninstaller(string uninstPath, string dir, string dataRoot)
        {
            string cscPath = FindCsc();
            if (cscPath == null) return;

            string escDir  = dir.Replace("\\", "\\\\").Replace("\"", "\\\"");
            string escData = dataRoot.Replace("\\", "\\\\").Replace("\"", "\\\"");

            StringBuilder src = new StringBuilder();
            src.Append("using System;using System.IO;using System.Windows.Forms;using System.Diagnostics;using Microsoft.Win32;");
            src.Append("class U{[STAThread]static void Main(){");
            src.Append("if(MessageBox.Show(\"Remove PA Pipeline, its virtual environment, and project_config.json?\",\"Uninstall\",");
            src.Append("MessageBoxButtons.YesNo,MessageBoxIcon.Question)!=DialogResult.Yes)return;");
            src.Append("try{");
            src.Append("string d=\"" + escDir + "\";");
            src.Append("string dd=\"" + escData + "\";");
            src.Append("string desk=Environment.GetFolderPath(Environment.SpecialFolder.DesktopDirectory);");
            src.Append("string lnk=Path.Combine(desk,\"PA Pipeline.lnk\");");
            src.Append("if(File.Exists(lnk))File.Delete(lnk);");
            src.Append("string sm=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Programs),\"PA Pipeline\");");
            src.Append("if(Directory.Exists(sm))Directory.Delete(sm,true);");
            src.Append("try{Registry.CurrentUser.DeleteSubKeyTree(\"Software\\\\Microsoft\\\\Windows\\\\CurrentVersion\\\\Uninstall\\\\PAPipeline\",false);}catch{}");
            src.Append("try{if(Directory.Exists(dd))Directory.Delete(dd,true);}catch{}");
            src.Append("Process.Start(new ProcessStartInfo(\"cmd.exe\",\"/C choice /T 2 /D Y /N >NUL && rmdir /S /Q \\\"\"+d+\"\\\"\"){WindowStyle=ProcessWindowStyle.Hidden,UseShellExecute=true});");
            src.Append("MessageBox.Show(\"PA Pipeline has been uninstalled.\",\"Done\",MessageBoxButtons.OK,MessageBoxIcon.Information);");
            src.Append("}catch(Exception ex){MessageBox.Show(\"Uninstall error: \"+ex.Message,\"Error\",MessageBoxButtons.OK,MessageBoxIcon.Error);}}}");

            string tempSrc = Path.Combine(Path.GetTempPath(),
                "PAUninst-" + Guid.NewGuid().ToString("N").Substring(0, 6) + ".cs");
            File.WriteAllText(tempSrc, src.ToString(), Encoding.UTF8);
            ProcessStartInfo psi2 = new ProcessStartInfo();
            psi2.FileName               = cscPath;
            psi2.Arguments              = "/nologo /target:winexe /r:System.Windows.Forms.dll /out:\"" + uninstPath + "\" \"" + tempSrc + "\"";
            psi2.UseShellExecute        = false;
            psi2.RedirectStandardOutput = true;
            psi2.RedirectStandardError  = true;
            psi2.CreateNoWindow         = true;
            Process pc = Process.Start(psi2);
            pc.WaitForExit();
            try { File.Delete(tempSrc); } catch {}
        }

        string FindCsc()
        {
            string[] paths = {
                @"C:\Windows\Microsoft.NET\Framework64\v4.0.30319\csc.exe",
                @"C:\Windows\Microsoft.NET\Framework\v4.0.30319\csc.exe",
                @"C:\Windows\Microsoft.NET\Framework64\v3.5\csc.exe",
                @"C:\Windows\Microsoft.NET\Framework\v3.5\csc.exe"
            };
            foreach (string p in paths)
                if (File.Exists(p)) return p;
            return null;
        }

        string JsonEscape(string s)
        {
            if (s == null) return "";
            return s.Replace("\\", "\\\\").Replace("\"", "\\\"");
        }

